/*
 * keeper PrimeVue Button + Tag/Badge/Chip overrides — transcribed from
 * temp-primevue-overrides.css during BD-B5 (2026-05-21). This block lives
 * identically in 4 places per the 4-way configOverrides duplication contract:
 *   - keeper/src/keeper/_index.yaml
 *   - keeper/src/keeper/git/_index.yaml
 *   - keeper/frontend/applications/keeper/package.json
 *   - keeper/plugins/git/frontend/applications/git/package.json
 * Maintenance rule (per CLAUDE.md "FE theming placement"): when one changes,
 * the other three must be updated to match.
 */

@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600&display=swap');

/* ----- Base geometry — match keeper's dense compact look ----- */
.p-button {
  border-radius: 4px;
  padding: 4px 12px;
  font-size: 11px;
  font-weight: 500;
  /* PrimeVue's default gap is 0.5rem (8px); keeper's hand-rolled buttons used
     4-5px between icon and label. Setting 4px here is the new default — call
     sites that need different gap should use !gap-1.5 / !gap-2 explicitly.
     Source-order: this file loads AFTER tailwind.css, so a plain `gap-N`
     Tailwind class WILL lose the specificity tie against this `.p-button`
     rule — use the `!`-modifier (e.g. `!gap-1.5`) to override. */
  gap: 4px;
  transition: none; /* keeper has no hover transition; PrimeVue's 0.2s shimmer feels off vs current */
}

.p-button-sm {
  padding: 2px 8px;
  font-size: 10px;
}

.p-button-lg {
  padding: 6px 14px;
  font-size: 12px;
}

/* ----- Filled severities (the "no text/outlined/link variant" selector chain
        excludes outline/text/link Buttons so they keep their transparent bg) ----- */

/* Default (no severity class) — primary. PrimeVue's default Button already
   renders bright primary-500 bg + white text in BOTH modes (verified B2), so
   bg/color/border don't need overriding. Only font-weight differs (PrimeVue
   defaults to 400, keeper .primary-btn is 600). Low-specificity selector
   (0,1,1) so .k-btn-* extension classes (0,2,0) can still win. */
.p-button:not([class*="p-button-"]) {
  font-weight: 600;
}

/* secondary — keeper's .header-btn look (light flat grey + bordered)
   keeper .header-btn padding is 4 10 (slightly narrower than base 4 12) */
.p-button-secondary:not(.p-button-text):not(.p-button-outlined):not(.p-button-link) {
  background: var(--p-content-hover-background); /* warm-grey surface-100 in keeper (#f4f4f5 / #2b2927) */
  color: var(--p-text-color);
  border-color: var(--p-content-border-color);
  padding: 4px 10px;
}

/* success — WCAG carve-out: -700 landed at 4.42 (just under AA 4.5),
   bumped to -800 in iter 5 to actually pass.
   keeper original was bg-success-500 + white text (≈2.2:1, AA fail) */
.p-button-success:not(.p-button-text):not(.p-button-outlined):not(.p-button-link) {
  background: var(--p-success-800);
  color: #fff;
  border-color: var(--p-success-800);
  font-weight: 600; /* keeper bg-success-500 = 600 */
}

/* info */
.p-button-info:not(.p-button-text):not(.p-button-outlined):not(.p-button-link) {
  background: var(--p-info-500);
  color: #fff;
  border-color: var(--p-info-500);
}

/* warn */
.p-button-warn:not(.p-button-text):not(.p-button-outlined):not(.p-button-link) {
  background: var(--p-warn-500);
  color: #fff;
  border-color: var(--p-warn-500);
}

/* help */
.p-button-help:not(.p-button-text):not(.p-button-outlined):not(.p-button-link) {
  background: var(--p-help-500);
  color: #fff;
  border-color: var(--p-help-500);
}

/* danger — WCAG carve-out: use -600 for better white-text contrast.
   keeper original was bg-danger-500 + white text (≈3.0:1, AA fail at 11px) */
.p-button-danger:not(.p-button-text):not(.p-button-outlined):not(.p-button-link) {
  background: var(--p-danger-600);
  color: #fff;
  border-color: var(--p-danger-600);
  /* font-weight stays 500 (keeper task-detail.vue:682 was 500) */
}

/* contrast — keep PrimeVue default if used */

/* ----- Text / Link variants — keeper's `btn-text-link` / `btn-toggle-text`
        have no chrome: transparent bg, no padding, no radius, weight 400 ----- */
.p-button-text,
.p-button-link {
  padding: 0;
  border-radius: 0;
  font-weight: 400;
}

/* Dark-mode primary-text brightening was here originally, but moved to the
   end of the file so its CSS source order beats `.k-btn-nav.k-btn-active`
   (which sets `color: primary-color` and is defined later than this point). */

/* ----- Disabled state — match keeper's faded-but-readable look ----- */
.p-button:disabled,
.p-button[disabled] {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ============================================================
   Keeper-specific extensions — for variants stock PrimeVue
   doesn't cover. Use with <Button class="k-btn-…">.
   ============================================================ */

/* k-btn-dashed — keeper's `.add-btn` (AgentEditor "+ Add" pattern).
   Standalone: do not combine with .p-button-outlined (handles its own
   bg/color/border so the call site is just <Button class="k-btn-dashed">). */
.p-button.k-btn-dashed {
  background: var(--p-content-background);
  color: var(--p-text-color);
  border: 1px dashed var(--p-surface-300);
  border-radius: 4px;
  padding: 4px 10px;
  font-size: 11px;
  font-weight: 400;
}
.p-button.k-btn-dashed:hover:not(:disabled) {
  border-color: var(--p-primary-color);
}

/* k-btn-nav — keeper's `.keeper-nav-btn` (styles.css:93-106). Transparent
   base with FULL text color (not muted — REJECT 1 in B4 code review);
   hover lifts bg to surface-100; .k-btn-active (or .active) keeps surface-100
   bg and swaps text to primary-color. */
.p-button.k-btn-nav {
  background: transparent;
  color: var(--p-text-color);
  border: 1px solid transparent;
  border-radius: 4px;
  padding: 4px 10px;
  font-size: 12px;
  font-weight: 500;
  /* match original `transition-colors` on .keeper-nav-btn (Tailwind default 150ms) */
  transition: background-color 150ms, color 150ms, border-color 150ms;
}
.p-button.k-btn-nav:hover {
  background: var(--p-surface-100);
}
.p-button.k-btn-nav.k-btn-active,
.p-button.k-btn-nav.active {
  background: var(--p-surface-100);
  color: var(--p-primary-color);
}

/* k-btn-icon — keeper's `.icon-btn` (mcp.vue:603-616) and similar
   bare-icon buttons. Transparent base, muted text, surface-200 hover bg
   with full text-color. Per-call-site metric tweaks via !-prefix Tailwind
   utilities (e.g. `!p-0.5` for DetailPanel close, `!w-6 !h-6 !rounded-full`
   for AppUserChip logout). */
.p-button.k-btn-icon {
  background: transparent;
  color: var(--p-text-muted-color);
  border: none;
  border-radius: 3px;
  padding: 4px;
  font-weight: 400;
}
.p-button.k-btn-icon:hover:not(:disabled) {
  background: var(--p-surface-200);
  color: var(--p-text-color);
}

/* k-btn-icon-danger — danger-on-hover variant (rm-btn, clear-btn,
   `.icon-btn.danger`). Layer on top of `.k-btn-icon`. */
.p-button.k-btn-icon.k-btn-icon-danger:hover:not(:disabled) {
  background: color-mix(in srgb, var(--p-danger-500) 15%, transparent);
  color: var(--p-danger-500);
}

/* k-btn-graph-ctrl — ForceGraph zoom controls.
   28×28 translucent surface, no border, monospace glyph. */
.p-button.k-btn-graph-ctrl {
  width: 28px;
  height: 28px;
  padding: 0;
  background: color-mix(in srgb, var(--p-content-hover-background) 80%, transparent);
  color: var(--p-text-color);
  border: none;
  border-radius: 4px;
  font-size: 14px;
  font-weight: 400;
  font-family: monospace; /* verified from ForceGraph.vue:375 */
}
.p-button.k-btn-graph-ctrl:hover:not(:disabled) {
  background: color-mix(in srgb, var(--p-content-border-color) 90%, transparent);
}

/* k-btn-tinted (+ severity modifier) — keeper's `bg-{sev}-500/10 text-{sev}-500`
   pattern. Base sets geometry; modifier sets the severity color.
   Use as: <Button class="k-btn-tinted k-btn-tinted-accent">Explain</Button>. */
.p-button.k-btn-tinted {
  padding: 2px 8px;
  font-size: 10px;
  font-weight: 400;
  border-color: transparent;
  border-radius: 4px;
}
/* WCAG carve-out: tinted variants use -700 text in light (severity-500 was
   ~2.0-3.3:1 AA fail on pale-bg-on-white) and -400 text in dark
   (severity-500 dark on dark page bg was borderline / fail for danger). */
.p-button.k-btn-tinted-primary { background: color-mix(in srgb, var(--p-primary-500) 10%, transparent); color: var(--p-primary-700); }
.p-button.k-btn-tinted-info    { background: color-mix(in srgb, var(--p-info-500)    10%, transparent); color: var(--p-info-700); }
.p-button.k-btn-tinted-success { background: color-mix(in srgb, var(--p-success-500) 10%, transparent); color: var(--p-success-800); } /* -700 hit 4.06; -800 to pass */
.p-button.k-btn-tinted-warn    { background: color-mix(in srgb, var(--p-warn-500)    10%, transparent); color: var(--p-warn-700); }
.p-button.k-btn-tinted-help    { background: color-mix(in srgb, var(--p-help-500)    10%, transparent); color: var(--p-help-700); }
.p-button.k-btn-tinted-danger  { background: color-mix(in srgb, var(--p-danger-500)  10%, transparent); color: var(--p-danger-700); }
.p-button.k-btn-tinted-accent  { background: color-mix(in srgb, var(--p-accent-500)  10%, transparent); color: var(--p-accent-800); } /* -700 hit 4.35; -800 to pass */

@media (prefers-color-scheme: dark) {
  .p-button.k-btn-tinted-primary { color: var(--p-primary-400); }
  .p-button.k-btn-tinted-info    { color: var(--p-info-400); }
  .p-button.k-btn-tinted-success { color: var(--p-success-400); }
  .p-button.k-btn-tinted-warn    { color: var(--p-warn-400); }
  .p-button.k-btn-tinted-help    { color: var(--p-help-400); }
  .p-button.k-btn-tinted-danger  { color: var(--p-danger-400); }
  .p-button.k-btn-tinted-accent  { color: var(--p-accent-400); }
}

/* k-btn-save — keeper's `.ed-save-btn` stateful save button.
   B3 collapse claim "<Button :disabled="!dirty">" was WRONG — keeper's
   clean state is surface-200 + muted text (not just opacity-faded primary).
   Use <Button class="k-btn-save" :disabled="!dirty"> instead. */
.p-button.k-btn-save {
  background: var(--p-primary-color);
  color: var(--p-primary-contrast-color);
  border-color: var(--p-primary-color);
  padding: 4px 12px;
  font-size: 11px;
  font-weight: 600;
}
.p-button.k-btn-save:hover:not(:disabled) {
  opacity: 0.9;
}
.p-button.k-btn-save:disabled,
.p-button.k-btn-save[disabled] {
  background: var(--p-surface-200);
  color: var(--p-text-muted-color);
  border-color: var(--p-surface-200);
  font-weight: 500;
  opacity: 1; /* override the global .p-button:disabled opacity */
  cursor: not-allowed;
}

/* ============================================================
   Hover states for filled severities + secondary + text+icon-only.
   Source captures (keeper hand-rolled originals):
     .primary-btn      :hover { opacity: .9 }
     .header-btn       :hover { background: surface-200; border-color: primary }
     .icon-btn         :hover { background: surface-200; color: text-color }
     .icon-btn.danger  :hover { background: danger@15%; color: danger-500 }
   ============================================================ */

/* Filled buttons (any severity, including default-primary): subtle dim on hover */
.p-button:hover:not(:disabled):not(.p-button-text):not(.p-button-outlined):not(.p-button-link) {
  opacity: 0.9;
}

/* Secondary (.header-btn) hover: stronger bg + primary-color border ring */
.p-button-secondary:not(.p-button-text):not(.p-button-outlined):not(.p-button-link):hover:not(:disabled) {
  opacity: 1; /* override the filled hover above; secondary uses bg shift not opacity */
  background: var(--p-surface-200);
  border-color: var(--p-primary-color);
}

/* Text icon-only (.icon-btn) hover: surface-200 bg + full text color */
.p-button-text.p-button-icon-only:hover:not(:disabled):not(.p-button-danger) {
  background: var(--p-surface-200);
  color: var(--p-text-color);
}

/* Text icon-only DANGER (.icon-btn.danger / .clear-btn) hover: danger-tint bg + danger text */
.p-button-text.p-button-icon-only.p-button-danger:hover:not(:disabled),
.p-button-text.p-button-danger:hover:not(:disabled) {
  background: color-mix(in srgb, var(--p-danger-500) 15%, transparent);
  color: var(--p-danger-500);
}

/* ============================================================
   D2 BD-B3 — Tag / Badge / Chip override layer for the Badge/Chip family.
   ============================================================
   DESIGN PRINCIPLE: lean into PrimeVue's own primitives (severity / size /
   removable props) so most call sites need NO keeper-specific class.
   Keeper layer is ONLY:
     - Base resets that bend Tag/Badge/Chip defaults to keeper's compact
       look (10px font, 4px radius, dense padding, tint-bg severities).
     - 4 slap-on classes for the patterns PrimeVue genuinely can't express:
       .k-tag-mono   — monospace + bordered (kind-badge)
       .k-tag-letter — fixed 18x18 single-char tile (op-letter)
       .k-tag-metric — neutral bordered + text-only severity (stat-pill)
       .k-chip-managed — success-tinted bordered chip (settings-registry)

   API SUMMARY for call sites:
     status-tinted:    <Tag severity="success">ok</Tag>                  (no class)
     neutral pill:     <Tag severity="secondary">…</Tag>                 (no class)
     kind-badge:       <Tag severity="secondary" class="k-tag-mono">agent.gen1</Tag>
     op-letter:        <Tag severity="success" class="k-tag-letter">A</Tag>
     count pill:       <Badge severity="secondary" :value="47" />        (no class)
     tab-cnt 8px:      <Badge severity="secondary" :value="3" size="small" />
     stat-pill:        <Tag severity="info" class="k-tag-metric">
                         <span class="k-tag-num">7</span><span class="k-tag-lbl">active</span>
                       </Tag>
     hero-pill 11px:   <Tag severity="warn" class="!text-[11px] !px-[9px] !py-[3px]">
                                                                          (3 utilities, ~4 sites)
     percentage-chip:  <Tag severity="secondary" class="!text-[9px]">42%</Tag>
                                                                          (1 utility, ~4 sites)
     removable-chip:   <Chip label="dev" removable />                    (no class)
     managed-chip:     <Chip label="x" removable class="k-chip-managed" />
     awaiting-pulse:   KEEP HAND-ROLLED (animation, 2 sites)

   For data-driven colors that exceed PrimeVue's severity enum (e.g.
   msgColor() returns var(--p-accent-500)), call sites use inline
   `:style="{ color: dataColor, background: 'color-mix(...)' }"`.

   Hand-rolled per BD-B1 plan (no Tag class): variants 4 (data-neutral),
   6 (filter-chip), 7 (dot), 8 (icon-bubble), 9 (kbd), 12 (awaiting-pulse).
   ============================================================ */

/* ----- Tag base reset ----- */
/* PrimeVue 4 default Tag is 0.25rem/0.5rem padding, 0.75rem font, 700
   weight, 16px radius (rounded chip). Keeper wants compact 10px / 4px
   radius / dense flat pills. */
.p-tag {
  padding: 2px 6px;
  font-size: 10px;
  font-weight: 400;
  border-radius: 4px;
  gap: 4px;
}

/* Severity classes → tint bg + severity-color text (status-tinted look).
   Higher specificity than PrimeVue's `.p-tag-success` alone, so our 10%
   tint wins over PrimeVue's solid severity fill.
   WCAG AA carve-out: -700 text (light mode) for AA contrast on the 10%
   tint bg; success bumps to -800 (-700 hit ~4.06:1, just under AA 4.5).
   Dark-mode brightening to -400 lives in the end-of-file @media block.
   This diverges from byte-identical-to-hand-rolled (keeper code uses
   -500); same divergence rule the Button family WCAG carve-out applied. */
.p-tag.p-tag-primary    { background: color-mix(in srgb, var(--p-primary-500) 10%, transparent); color: var(--p-primary-700); }
.p-tag.p-tag-success    { background: color-mix(in srgb, var(--p-success-500) 10%, transparent); color: var(--p-success-800); }
.p-tag.p-tag-info       { background: color-mix(in srgb, var(--p-info-500) 10%, transparent); color: var(--p-info-700); }
.p-tag.p-tag-warn       { background: color-mix(in srgb, var(--p-warn-500) 10%, transparent); color: var(--p-warn-700); }
.p-tag.p-tag-danger     { background: color-mix(in srgb, var(--p-danger-500) 10%, transparent); color: var(--p-danger-700); }
.p-tag.p-tag-help       { background: color-mix(in srgb, var(--p-help-500) 10%, transparent); color: var(--p-help-700); }
/* secondary → neutral surface pill (covers model-pill, count-pill use of Tag,
   percentage-chip with !-utility size override). Muted text on surface-100
   is ~4.5:1 in light, ~5.4:1 in dark — AA-passing already, no carve-out. */
.p-tag.p-tag-secondary  { background: var(--p-surface-100); color: var(--p-text-muted-color); }
/* contrast → inverted text-on-bg (not in keeper's current usage per BD-B1
   plan, but completes PrimeVue 4's full Tag severity enum). High-contrast
   pair by construction; tokens auto-flip light/dark. */
.p-tag.p-tag-contrast   { background: var(--p-text-color); color: var(--p-content-background); }

/* ----- Badge base reset (counter family) ----- */
/* PrimeVue 4 default Badge is circular `min-width: 1.5rem; height: 1.5rem;
   border-radius: 50%` with bold primary fill. Keeper's count pills are
   rectangular small muted neutral chips. After merge A: ns-count + hdr-count
   unify into one default Badge look. */
.p-badge {
  min-width: auto;
  height: auto;
  padding: 2px 8px;
  font-size: 10px;
  font-weight: 500;
  border-radius: 10px;
  background: var(--p-surface-100);
  color: var(--p-text-muted-color);
  gap: 0;
}
/* tab-cnt — PrimeVue's `size="small"` prop applies .p-badge-sm */
.p-badge.p-badge-sm {
  font-size: 8px;
  font-weight: 400;
  padding: 0 4px;
  border-radius: 6px;
  background: var(--p-surface-200);
  color: var(--p-text-color);
}

/* Badge severity colors — mirror the Tag tint logic (10% bg + severity
   text) so severity-colored counters read as soft accents, not loud
   solid PrimeVue defaults. Keeper currently only uses severity="secondary"
   for counters (the base reset above covers it), but these complete the
   PrimeVue 4 severity enum so any future usage stays on-design without
   per-call overrides. Same WCAG carve-out as Tag: -700 text in light
   (success bumps to -800), -400 in dark (via @media at EOF). */
.p-badge.p-badge-primary  { background: color-mix(in srgb, var(--p-primary-500) 10%, transparent); color: var(--p-primary-700); }
.p-badge.p-badge-success  { background: color-mix(in srgb, var(--p-success-500) 10%, transparent); color: var(--p-success-800); }
.p-badge.p-badge-info     { background: color-mix(in srgb, var(--p-info-500) 10%, transparent); color: var(--p-info-700); }
.p-badge.p-badge-warn     { background: color-mix(in srgb, var(--p-warn-500) 10%, transparent); color: var(--p-warn-700); }
.p-badge.p-badge-danger   { background: color-mix(in srgb, var(--p-danger-500) 10%, transparent); color: var(--p-danger-700); }
.p-badge.p-badge-help     { background: color-mix(in srgb, var(--p-help-500) 10%, transparent); color: var(--p-help-700); }
.p-badge.p-badge-contrast { background: var(--p-text-color); color: var(--p-content-background); }

/* ----- Chip base reset (removable chip family) ----- */
/* PrimeVue 4 default Chip is large rounded-full. Keeper wants the .tag
   shape from TagsField — small surface-200 neutral with embedded x. */
.p-chip {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  padding: 1px 6px;
  border-radius: 3px;
  font-size: 10px;
  font-weight: 400;
  background: var(--p-surface-200);
  color: var(--p-text-color);
  border: 0;
}
.p-chip .p-chip-remove-icon {
  width: 10px;
  height: 10px;
  color: var(--p-text-muted-color);
  cursor: pointer;
}
.p-chip .p-chip-remove-icon:hover {
  color: var(--p-danger-500);
}

/* ============================================================
   Keeper slap-on classes (4) — only for patterns PrimeVue can't express
   ============================================================ */

/* k-tag-mono — kind-badge (mono + bordered + tighter padding).
   PrimeVue Tag has no font-family token, and Tag's severity-tinted base
   has no border. Override both here. */
.p-tag.k-tag-mono {
  font-family: 'JetBrains Mono', ui-monospace, SFMono-Regular, monospace;
  border-radius: 3px;
  padding: 1px 8px;
  background: var(--p-surface-100);
  color: var(--p-text-color);
  border: 1px solid var(--p-content-border-color);
}

/* k-tag-letter — op-letter (18x18 single-char square tile).
   PrimeVue has no fixed-size variant. The severity class adds tint bg
   + severity color (inherited from base reset above). */
.p-tag.k-tag-letter {
  width: 18px;
  height: 18px;
  padding: 0;
  font-size: 9px;
  font-weight: 600;
  border-radius: 3px;
  font-family: ui-monospace, SFMono-Regular, monospace;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0;
}

/* k-tag-metric — stat-pill (neutral bordered, text-only severity recolor).
   This fights PrimeVue's severity-recolors-bg model: we want neutral
   surface-100 bg + bordered, with severity recoloring TEXT ONLY. The
   per-severity rules below pin bg/border to neutral and override only
   the color. */
.p-tag.k-tag-metric {
  padding: 3px 9px;
  border-radius: 4px;
  background: var(--p-surface-100);
  border: 1px solid var(--p-content-border-color);
  font-size: 11px;
  font-weight: 400;
  color: var(--p-text-color);
  gap: 5px;
}
/* The per-severity rules pin bg/border to neutral and override the text
   color only. Covers the full PrimeVue 4 severity enum so any keeper
   metric can be tone-coded. accent / arbitrary data-driven colors use
   `:style="{ color: var(--p-accent-500) }"` on the call site instead.
   Same WCAG carve-out: -700 text in light (success bumps to -800),
   -400 in dark (@media at EOF). surface-100 bg has ~same contrast as
   the 10% tint of severity-on-white, so same bumps apply. */
.p-tag.k-tag-metric.p-tag-primary   { color: var(--p-primary-700); background: var(--p-surface-100); border-color: var(--p-content-border-color); }
.p-tag.k-tag-metric.p-tag-secondary { color: var(--p-text-muted-color); background: var(--p-surface-100); border-color: var(--p-content-border-color); }
.p-tag.k-tag-metric.p-tag-success   { color: var(--p-success-800); background: var(--p-surface-100); border-color: var(--p-content-border-color); }
.p-tag.k-tag-metric.p-tag-info      { color: var(--p-info-700); background: var(--p-surface-100); border-color: var(--p-content-border-color); }
.p-tag.k-tag-metric.p-tag-warn      { color: var(--p-warn-700); background: var(--p-surface-100); border-color: var(--p-content-border-color); }
.p-tag.k-tag-metric.p-tag-danger    { color: var(--p-danger-700); background: var(--p-surface-100); border-color: var(--p-content-border-color); }
.p-tag.k-tag-metric.p-tag-help      { color: var(--p-help-700); background: var(--p-surface-100); border-color: var(--p-content-border-color); }
.p-tag.k-tag-metric.p-tag-contrast  { color: var(--p-text-color); background: var(--p-surface-100); border-color: var(--p-content-border-color); }
/* Inner two-tone helpers — used inside .k-tag-metric default slot.
   Not counted as "slap-on classes" — call sites use them on inner spans. */
.k-tag-num { font-weight: 700; font-variant-numeric: tabular-nums; }
.k-tag-lbl { font-size: 10px; color: var(--p-text-muted-color); }

/* k-tag-tone-accent — keeper-extension severity (not in PrimeVue's enum).
   Used by `.stat-pill--accent` and msgColor() returns for function/delegation/
   developer message types. Works standalone (tinted accent pill) or with
   `.k-tag-metric` (neutral metric with accent text). WCAG-aware: -800 in
   light (mirrors .k-btn-tinted-accent — -700 hit 4.35:1 under AA 4.5),
   -400 in dark (via @media at EOF). */
.p-tag.k-tag-tone-accent {
  background: color-mix(in srgb, var(--p-accent-500) 10%, transparent);
  color: var(--p-accent-800);
}
.p-tag.k-tag-metric.k-tag-tone-accent {
  background: var(--p-surface-100);
  border-color: var(--p-content-border-color);
  color: var(--p-accent-800);
}

/* k-chip-managed — settings-registry success-tinted clickable variant.
   Keeper-specific tint of Chip not expressible via Chip's prop API. */
.p-chip.k-chip-managed {
  padding: 2px 6px 2px 8px;
  border-radius: 4px;
  border: 1px solid color-mix(in srgb, var(--p-success-500) 30%, transparent);
  background: color-mix(in srgb, var(--p-success-500) 12%, transparent);
  color: var(--p-text-color);
  font-family: ui-monospace, SFMono-Regular, monospace;
  font-size: 11px;
  gap: 4px;
  cursor: pointer;
}

/* ============================================================
   END-OF-FILE: dark-mode WCAG brightening — placed last so source
   order beats any earlier rules that set primary-color on the same
   selectors (notably .k-btn-nav.k-btn-active above).
   ============================================================ */
@media (prefers-color-scheme: dark) {
  /* Button dark-mode brightening (text/outlined/link primary text + nav-active) */
  .p-button-text:not(.p-button-danger),
  .p-button-outlined,
  .p-button-link,
  .p-button.k-btn-nav.k-btn-active,
  .p-button.k-btn-nav.active {
    color: var(--p-primary-400);
  }

  /* Tag / Badge / k-tag-metric severity text — dark-mode WCAG carve-out:
     -400 text reads bright against the dark-page-composited tint bg
     (or against surface-100 dark for k-tag-metric). Mirrors the
     Button family `.k-btn-tinted-*` dark-mode rule. */
  .p-tag.p-tag-primary,
  .p-badge.p-badge-primary,
  .p-tag.k-tag-metric.p-tag-primary  { color: var(--p-primary-400); }
  .p-tag.p-tag-success,
  .p-badge.p-badge-success,
  .p-tag.k-tag-metric.p-tag-success  { color: var(--p-success-400); }
  .p-tag.p-tag-info,
  .p-badge.p-badge-info,
  .p-tag.k-tag-metric.p-tag-info     { color: var(--p-info-400); }
  .p-tag.p-tag-warn,
  .p-badge.p-badge-warn,
  .p-tag.k-tag-metric.p-tag-warn     { color: var(--p-warn-400); }
  .p-tag.p-tag-danger,
  .p-badge.p-badge-danger,
  .p-tag.k-tag-metric.p-tag-danger   { color: var(--p-danger-400); }
  .p-tag.p-tag-help,
  .p-badge.p-badge-help,
  .p-tag.k-tag-metric.p-tag-help     { color: var(--p-help-400); }
  .p-tag.k-tag-tone-accent,
  .p-tag.k-tag-metric.k-tag-tone-accent { color: var(--p-accent-400); }
}
